import torch
from typing import Any

def to_device(obj: Any, device: torch.device) -> Any:
    """Recursively move tensors in nested dicts/lists to device."""
    if isinstance(obj, torch.Tensor):
        return obj.to(device, non_blocking=True)
    elif isinstance(obj, dict):
        return {k: to_device(v, device) for k, v in obj.items()}
    elif isinstance(obj, (list, tuple)):
        return type(obj)(to_device(v, device) for v in obj)
    return obj


def safe_training_step(model, batch, device):
    try:
        batch = to_device(batch, device)
        output = model(**batch)
        return output.loss
    except RuntimeError as e:
        if "out of memory" in str(e).lower():
            torch.cuda.empty_cache()
            print(f"OOM on batch shape {batch['input_ids'].shape} — consider reducing batch_size")
            return None
        raise


# Startup check — run before any training
def assert_gpu_ready():
    assert torch.cuda.is_available(), "CUDA not available — check drivers"
    print(f"Training on: {torch.cuda.get_device_name(0)}")
    print(f"VRAM: {torch.cuda.get_device_properties(0).total_memory / 1e9:.1f} GB")
    # Sanity check: tiny op on GPU
    x = torch.randn(10, 10, device='cuda')
    _ = x @ x
    print("GPU compute check passed")
